import {
  Box,
  Button,
  FormControl,
  FormLabel,
  Input,
  Textarea,
  Heading,
  Image,
  Flex,
  Text,
} from "@chakra-ui/react";
import React, { useState } from "react";

import TeacherNavTop from "./TeacherNavTop";
import { useDispatch } from "react-redux";
import { addProduct } from "../../Redux/TeacherReducer/action";
import { useNavigate } from "react-router-dom";

const AddTeacherCourse = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const [detail, setDetail] = useState({
    title: "",
    description: "",
    category: "",
    price: "",
    img: "",
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setDetail((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = () => {
    dispatch(addProduct(detail));
    alert("Course Added Successfully");
    navigate("/Teacher/courses");
  };

  return (
    <>
      <TeacherNavTop />

      <Flex
        bg="#f7f9fa"
        minH="100vh"
        justify="center"
        align="center"
        p={5}
      >
        <Box
          bg="white"
          p={8}
          borderRadius="lg"
          boxShadow="lg"
          w="100%"
          maxW="600px"
        >
          {/* TITLE */}
          <Heading size="lg" mb={6}>
            Create New Course
          </Heading>

          {/* FORM */}
          <FormControl mb={4}>
            <FormLabel>Course Title</FormLabel>
            <Input
              placeholder="e.g. Complete Node.js Bootcamp"
              name="title"
              value={detail.title}
              onChange={handleChange}
              _focus={{ borderColor: "#A435F0" }}
            />
          </FormControl>

          <FormControl mb={4}>
            <FormLabel>Description</FormLabel>
            <Textarea
              placeholder="Write a short description..."
              name="description"
              value={detail.description}
              onChange={handleChange}
              _focus={{ borderColor: "#A435F0" }}
            />
          </FormControl>

          <FormControl mb={4}>
            <FormLabel>Category</FormLabel>
            <Input
              placeholder="e.g. Development"
              name="category"
              value={detail.category}
              onChange={handleChange}
              _focus={{ borderColor: "#A435F0" }}
            />
          </FormControl>

          <FormControl mb={4}>
            <FormLabel>Price (₹)</FormLabel>
            <Input
              type="number"
              placeholder="e.g. 499"
              name="price"
              value={detail.price}
              onChange={handleChange}
              _focus={{ borderColor: "#A435F0" }}
            />
          </FormControl>

          <FormControl mb={4}>
            <FormLabel>Thumbnail URL</FormLabel>
            <Input
              placeholder="Paste image link..."
              name="img"
              value={detail.img}
              onChange={handleChange}
              _focus={{ borderColor: "#A435F0" }}
            />
          </FormControl>

          {/* PREVIEW IMAGE */}
          {detail.img && (
            <Box mb={4}>
              <Text fontSize="sm" mb={2} color="gray.600">
                Preview
              </Text>
              <Image
                src={detail.img}
                borderRadius="md"
                maxH="180px"
                objectFit="cover"
              />
            </Box>
          )}

          {/* BUTTON */}
          <Button
            bg="#A435F0"
            color="white"
            w="100%"
            size="lg"
            _hover={{ bg: "#8710d8" }}
            onClick={handleSubmit}
          >
            Create Course
          </Button>
        </Box>
      </Flex>
    </>
  );
};

export default AddTeacherCourse;
